def esc(value):
    return html.escape(str(value or ""))


def money(value):
    try:
        return f"{float(value):,.0f}"
    except Exception:
        return "0"


def pct(value):
    try:
        return f"{float(value):.1f}%"
    except Exception:
        return "0.0%"


def ts():
    return int(time.time())


PAGE_CACHE = {}


def cached_page_data(key, ttl_seconds, builder):
    now = time.time()
    cached = PAGE_CACHE.get(key)
    if cached and now - cached[0] <= ttl_seconds:
        return cached[1]
    value = builder()
    PAGE_CACHE[key] = (now, value)
    return value


def dt(value):
    try:
        return time.strftime("%Y-%m-%d %H:%M", time.localtime(int(value or 0)))
    except Exception:
        return ""


def safe_json(value, fallback=None):
    try:
        return json.loads(value or "")
    except Exception:
        return fallback if fallback is not None else {}


def pg_config():
    host = os.environ.get("PG_HOST") or os.environ.get("POSTGRES_HOST") or "postgres"
    dbname = os.environ.get("PG_DB") or os.environ.get("POSTGRES_DB")
    user = os.environ.get("PG_USER") or os.environ.get("POSTGRES_USER")
    password = os.environ.get("PG_PASSWORD") or os.environ.get("POSTGRES_PASSWORD")
    if not all([host, dbname, user, password]):
        return None
    return {
        "host": host,
        "port": int(os.environ.get("PG_PORT") or os.environ.get("POSTGRES_PORT") or "5432"),
        "dbname": dbname,
        "user": user,
        "password": password,
        "connect_timeout": int(os.environ.get("PG_CONNECT_TIMEOUT", "3")),
    }


def pg_query(sql, params=None):
    cfg = pg_config()
    if not cfg or not psycopg2:
        return []
    try:
        with psycopg2.connect(**cfg) as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(sql, params or ())
                return [dict(row) for row in cur.fetchall()]
    except Exception:
        return []


def _legacy_pg_summary():
    # Kept only for database migration compatibility; application routes never call it.
    return None
    latest_rows = pg_query(
        """
select sales_date, sales_amount, gross_profit
from sap_daily_sales_summary
where sales_date = (select max(sales_date) from sap_daily_sales_summary)
"""
    )
    if not latest_rows:
        return None
    latest = latest_rows[0]
    data_date = latest.get("sales_date")
    month_rows = pg_query(
        """
select coalesce(sum(sales_amount),0) as month_sales, coalesce(sum(gross_profit),0) as month_gross_profit
from sap_daily_sales_summary
where date_trunc('month', sales_date) = date_trunc('month', %s::date)
""",
        (data_date,),
    )
    store_rows = pg_query(
        """
select whs_code as store, coalesce(sum(sales_amount),0) as sales, coalesce(sum(gross_profit),0) as gross_profit
from sap_store_sales_summary
where date_trunc('month', sales_date) = date_trunc('month', %s::date)
group by whs_code
order by coalesce(sum(sales_amount),0) desc
limit 12
""",
        (data_date,),
    )
    inv_rows = pg_query(
        """
select
 coalesce(sum(on_hand * avg_price),0) as inventory_amount,
 count(*) filter (where on_hand > 20 and coalesce(is_commited,0) = 0) as risk_count
from sap_stock_by_whs
where on_hand > 0
"""
    )
    run_rows = pg_query("select status, finished_at from sap_sync_runs order by started_at desc, id desc limit 1")
    month = month_rows[0] if month_rows else {}
    inv = inv_rows[0] if inv_rows else {}
    yesterday_sales = float(latest.get("sales_amount") or 0)
    yesterday_gross_profit = float(latest.get("gross_profit") or 0)
    month_sales = float(month.get("month_sales") or 0)
    month_gross_profit = float(month.get("month_gross_profit") or 0)
    month_target = float(os.environ.get("MONTH_TARGET", "900000") or 900000)
    gross_margin = yesterday_gross_profit / yesterday_sales * 100 if yesterday_sales else 0
    completion = month_sales / month_target * 100 if month_target else 0
    top_stores = [
        {
            "store": row.get("store") or U(r"\u672a\u5206\u95e8\u5e97"),
            "sales": float(row.get("sales") or 0),
            "gross_profit": float(row.get("gross_profit") or 0),
        }
        for row in store_rows
    ]
    risk_count = int(inv.get("risk_count") or 0)
    suggestions = [
        U(r"\u672c\u6708\u9500\u552e\u5b8c\u6210\u7387 ") + pct(completion) + U(r"\uff0c\u4eca\u5929\u4f18\u5148\u770b\u95e8\u5e97\u6392\u884c\u548c\u5dee\u989d\u3002"),
        U(r"\u6700\u65b0\u65e5\u6bdb\u5229\u7387 ") + pct(gross_margin) + U(r"\uff0c\u4f4e\u6bdb\u5229\u5355\u636e\u8981\u56de\u5230 SAP \u660e\u7ec6\u590d\u6838\u3002"),
        U(r"\u5e93\u5b58\u98ce\u9669\u6570\u91cf ") + money(risk_count) + U(r"\uff0c\u5148\u6309\u95e8\u5e97\u548c\u53ef\u8c03\u62e8\u4f18\u5148\u7ea7\u62c6\u89e3\u3002"),
    ]
    return {
        "data_date": str(data_date or ""),
        "yesterday_sales": yesterday_sales,
        "yesterday_gross_profit": yesterday_gross_profit,
        "yesterday_gross_margin": gross_margin,
        "month_sales": month_sales,
        "month_gross_profit": month_gross_profit,
        "month_target": month_target,
        "completion_rate": completion,
        "inventory_amount": float(inv.get("inventory_amount") or 0),
        "risk_count": risk_count,
        "top_stores": top_stores,
        "top_brands": [],
        "ai_suggestions": suggestions,
        "todos": [
            U(r"\u6253\u5f00\u9500\u552e\u548c\u6bdb\u5229\u5f02\u5e38\u95e8\u5e97\u6e05\u5355\u3002"),
            U(r"\u628a\u5e93\u5b58\u98ce\u9669\u6309\u54c1\u724c\u3001\u95e8\u5e97\u3001\u5c3a\u7801\u5206\u7ec4\u5904\u7406\u3002"),
            U(r"\u786e\u8ba4\u4eca\u665a SAP B1 \u540c\u6b65\u8c03\u5ea6\u662f\u5426\u6b63\u5e38\u6267\u884c\u3002"),
        ],
        "_source": "postgres:sap_*",
        "_is_fallback": False,
        "_loaded_at": ts(),
        "_last_sync_status": (run_rows[0].get("status") if run_rows else ""),
        "_last_sync_time": str(run_rows[0].get("finished_at") or "") if run_rows else "",
    }


_ENTERPRISE_DATA_CLIENT = {"key": None, "client": None}


def sap_live_summary():
    """Read the CEO operating summary from Core; local legacy data is opt-in only."""
    if build_enterprise_data_client:
        base_url = os.environ.get("CORE_BASE_URL", "https://core.vafox.com")
        token = os.environ.get("CORE_API_TOKEN", "")
        if token:
            try:
                key = (base_url, token)
                if _ENTERPRISE_DATA_CLIENT["key"] != key:
                    _ENTERPRISE_DATA_CLIENT["key"] = key
                    _ENTERPRISE_DATA_CLIENT["client"] = build_enterprise_data_client(
                        base_url,
                        token,
                        timeout=int(os.environ.get("CORE_API_TIMEOUT", "8")),
                        cache_seconds=int(os.environ.get("CORE_API_CACHE_SECONDS", "60")),
                    )
                result = _ENTERPRISE_DATA_CLIENT["client"].summary()
            except ValueError:
                result = {"ok": False}
            if result.get("ok") and isinstance(result.get("data"), dict):
                value = result["data"]
                sales = float(value.get("sales_amount") or 0)
                gross_profit = float(value.get("gross_profit") or 0)
                gross_margin = gross_profit / sales * 100 if sales else 0
                top_stores = [
                    {
                        "store": row.get("name") or row.get("id") or U(r"\u672a\u5206\u95e8\u5e97"),
                        "sales": float(row.get("sales_90d") or 0),
                        "gross_profit": float(row.get("gross_profit_90d") or 0),
                    }
                    for row in value.get("top_stores", [])
                ]
                top_brands = [
                    {"brand": row.get("name") or row.get("id"), "sales": float(row.get("sales_amount_90d") or 0)}
                    for row in value.get("top_brands", [])
                ]
                return {
                    "data_date": str(value.get("data_date") or ""),
                    "yesterday_sales": sales,
                    "yesterday_gross_profit": gross_profit,
                    "yesterday_gross_margin": gross_margin,
                    "month_sales": sales,
                    "month_gross_profit": gross_profit,
                    "month_target": float(os.environ.get("MONTH_TARGET", "900000") or 900000),
                    "completion_rate": 0,
                    "inventory_amount": float(value.get("stock_amount") or 0),
                    "risk_count": 0,
                    "top_stores": top_stores,
                    "top_brands": top_brands,
                    "ai_suggestions": [],
                    "todos": [],
                    "_source": "core.vafox.com/api/v1/business/summary",
                    "_is_fallback": False,
                    "_loaded_at": ts(),
                    "_last_sync_status": "read_only",
                    "_last_sync_time": str(value.get("data_as_of") or ""),
                }
    return None


def csv_values(value):
    return [v.strip() for v in str(value or "").split(",") if v.strip()]


def chunk_text(text, size=1600):
    clean = re.sub(r"\s+", " ", text or "").strip()
    if not clean:
        return []
    return [clean[i : i + size] for i in range(0, len(clean), size)]


def row_dict(row):
    return dict(row) if row else None


def module_key(path_or_key):
    return str(path_or_key or "").strip().lstrip("/")


def module_title(key):
    data = MODULES.get("/" + module_key(key))
    return data[0] if data else module_key(key)


def classify_text(text, fallback="01_公司制度"):
    text = (text or "").lower()
    rules = [
        ("02_产品资料", ["产品", "货号", "尺码", "面料", "价格", "gtx", "gore", "kailas"]),
        ("03_品牌资料", ["品牌", "logo", "合同", "mammut", "osprey", "salomon"]),
        ("04_销售话术", ["话术", "顾客", "推荐", "成交", "异议"]),
        ("06_门店经营", ["门店", "店长", "销售", "日报", "任务"]),
        ("07_库存采购", ["库存", "采购", "供应商", "订货", "补货"]),
        ("09_财务经营", ["财务", "付款", "现金", "社保", "工资", "公积金"]),
        ("14_AI经营日报", ["ai", "晨报", "经营分析", "建议"]),
    ]
    for category, words in rules:
        if any(w.lower() in text for w in words):
            return category
    return fallback


def summarize_text(text, limit=220):
    clean = re.sub(r"\s+", " ", text or "").strip()
    if not clean:
        return U(r"\u6682\u65e0\u53ef\u63d0\u53d6\u6587\u672c\uff0c\u5df2\u5148\u4fdd\u5b58\u539f\u6587\u4ef6\u3002")
    return clean[:limit] + ("..." if len(clean) > limit else "")


def extract_tags(text):
    category = classify_text(text)
    tags = [category.split("_", 1)[-1]]
    for word in [U(r"\u9500\u552e"), U(r"\u5e93\u5b58"), U(r"\u91c7\u8d2d"), U(r"\u4f1a\u5458"), U(r"\u95e8\u5e97"), "SAP B1", "AI"]:
        if word.lower() in (text or "").lower():
            tags.append(word)
    return ",".join(dict.fromkeys(tags))


def extract_file_text(path, filename):
    ext = Path(filename).suffix.lower()
    try:
        if ext in (".txt", ".md", ".csv", ".json"):
            return Path(path).read_text(encoding="utf-8", errors="ignore")[:200000]
        if ext == ".pdf":
            try:
                import pypdf
                reader = pypdf.PdfReader(path)
                return "\n".join("[第{}页]\n{}".format(index + 1, page.extract_text() or "") for index, page in enumerate(reader.pages))[:200000]
            except Exception:
                return ""
        if ext == ".docx":
            try:
                import docx
                doc = docx.Document(path)
                return "\n".join("[第{}段] {}".format(index + 1, paragraph.text) for index, paragraph in enumerate(doc.paragraphs) if paragraph.text.strip())[:200000]
            except Exception:
                return ""
        if ext in (".xlsx", ".xls"):
            try:
                import openpyxl
                wb = openpyxl.load_workbook(path, read_only=True, data_only=True)
                lines = []
                for ws in wb.worksheets[:3]:
                    lines.append("[工作表：{}]".format(ws.title))
                    for row_number, row in enumerate(ws.iter_rows(max_row=200, values_only=True), 1):
                        lines.append("第{}行\t{}".format(row_number, "\t".join("" if v is None else str(v) for v in row)))
                return "\n".join(lines)[:200000]
            except Exception:
                return ""
    except Exception:
        return ""
    return ""


def fetch_url_text(url):
    if not url.lower().startswith(("http://", "https://")):
        return ""
    try:
        req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0 VAFOX"})
        with urllib.request.urlopen(req, timeout=10) as resp:
            raw = resp.read(500000)
        text = raw.decode("utf-8", errors="ignore")
        text = re.sub(r"(?is)<script.*?</script>|<style.*?</style>", " ", text)
        text = re.sub(r"(?s)<[^>]+>", " ", text)
        return re.sub(r"\s+", " ", html.unescape(text)).strip()[:200000]
    except Exception:
        return ""


def ai_provider_config():
    provider = (os.environ.get("AI_PROVIDER") or os.environ.get("AI_DEFAULT_PROVIDER") or "").strip().lower()
    key = (
        os.environ.get("AI_API_KEY")
        or os.environ.get("DEEPSEEK_API_KEY")
        or os.environ.get("OPENAI_API_KEY")
        or os.environ.get("DASHSCOPE_API_KEY")
        or ""
    ).strip()
    if not provider:
        if os.environ.get("DEEPSEEK_API_KEY"):
            provider = "deepseek"
        elif os.environ.get("DASHSCOPE_API_KEY"):
            provider = "qwen"
        elif os.environ.get("OPENAI_API_KEY"):
            provider = "openai"
        else:
            provider = "openai_compatible"
    base_url = (os.environ.get("AI_BASE_URL") or os.environ.get("OPENAI_BASE_URL") or "").strip()
    if not base_url:
        if provider == "deepseek":
            base_url = "https://api.deepseek.com"
        elif provider in ("qwen", "dashscope"):
            base_url = "https://dashscope.aliyuncs.com/compatible-mode/v1"
        else:
            base_url = "https://api.openai.com/v1"
    model = (os.environ.get("AI_MODEL_NAME") or os.environ.get("AI_MODEL") or "").strip()
    if not model:
        if provider == "deepseek":
            model = "deepseek-chat"
        elif provider in ("qwen", "dashscope"):
            model = "qwen-plus"
        else:
            model = "gpt-4o-mini"
    endpoint = base_url.rstrip("/")
    if not endpoint.endswith("/chat/completions"):
        endpoint += "/chat/completions"
    return {
        "configured": bool(key),
        "provider": provider,
        "api_key": key,
        "base_url": base_url,
        "endpoint": endpoint,
        "model": model,
        "timeout": int(os.environ.get("AI_REQUEST_TIMEOUT", "45")),
        "max_tokens": int(os.environ.get("AI_MAX_TOKENS", "900")),
    }


def call_ai_chat(messages, temperature=0.2):
    cfg = ai_provider_config()
    if not cfg["configured"]:
        return {"ok": False, "reason": "not_configured", "config": cfg}
    payload = {
        "model": cfg["model"],
        "messages": messages,
        "temperature": temperature,
        "max_tokens": cfg["max_tokens"],
        "stream": False,
    }
    try:
        req = urllib.request.Request(
            cfg["endpoint"],
            data=json.dumps(payload, ensure_ascii=False).encode("utf-8"),
            headers={
                "Authorization": "Bearer " + cfg["api_key"],
                "Content-Type": "application/json",
                "User-Agent": "VAFOX/1.0",
            },
            method="POST",
        )
        with urllib.request.urlopen(req, timeout=cfg["timeout"]) as resp:
            data = json.loads(resp.read().decode("utf-8", errors="ignore"))
        content = data.get("choices", [{}])[0].get("message", {}).get("content", "")
        if not content:
            return {"ok": False, "reason": "empty_response", "config": cfg}
        return {"ok": True, "content": content.strip(), "config": cfg, "raw": data}
    except Exception as exc:
        return {"ok": False, "reason": "request_failed", "error": str(exc)[:300], "config": cfg}


def prompt_json(data, limit=9000):
    try:
        text = json.dumps(data, ensure_ascii=False, default=str)
    except Exception:
        text = str(data)
    return text[:limit]


