    def data_lake_hash(self, payload):
        text = json.dumps(payload or {}, ensure_ascii=False, sort_keys=True, default=str)
        return hashlib.sha256(text.encode("utf-8")).hexdigest()

    def normalize_store_name(self, value):
        text = (value or "").strip()
        replacements = {
            U(r"\u5357\u5c71\u5e97\u96f6\u552e\u5ba2\u6237"): U(r"\u5357\u5c71\u5e97"),
            U(r"\u5357\u5c71\u5e97\u6279\u53d1\u5ba2\u6237"): U(r"\u5357\u5c71\u5e97"),
            U(r"\u5357\u5c71\u5e97\u6279\u53d1\u5ba2\u6237-1"): U(r"\u5357\u5c71\u5e97"),
            U(r"\u5357\u5c71\u5e97\u5206\u9500\u5ba2\u6237"): U(r"\u5357\u5c71\u5e97"),
            U(r"\u632f\u5174\u5e97\u96f6\u552e\u5ba2\u6237"): U(r"\u632f\u5174\u5e97"),
            U(r"\u632f\u5174\u5e97\u6279\u53d1\u5ba2\u6237"): U(r"\u632f\u5174\u5e97"),
            U(r"\u632f\u5174\u5e97\u5206\u9500\u5ba2\u6237"): U(r"\u632f\u5174\u5e97"),
            U(r"\u632f\u5174\u5e97\u4f1a\u5458\u5ba2\u6237"): U(r"\u632f\u5174\u5e97"),
            U(r"\u822a\u82d1\u5e97\u96f6\u552e\u5ba2\u6237"): U(r"\u822a\u82d1\u5e97"),
            U(r"\u822a\u82d1\u5e97\u6279\u53d1\u5ba2\u6237"): U(r"\u822a\u82d1\u5e97"),
            U(r"\u822a\u82d1\u5e97\u5206\u9500\u5ba2\u6237"): U(r"\u822a\u82d1\u5e97"),
            U(r"\u91d1\u6c99\u5e97\u96f6\u552e\u5ba2\u6237"): U(r"\u91d1\u6c99\u5e97"),
            U(r"\u5fae\u5e97\u96f6\u552e\u5ba2\u6237"): U(r"\u5fae\u5e97"),
            U(r"\u7f51\u5e97\u96f6\u552e\u5ba2\u6237"): U(r"\u7f51\u5e97"),
        }
        if text in replacements:
            return replacements[text]
        for store in [U(r"\u5357\u5c71\u5e97"), U(r"\u632f\u5174\u5e97"), U(r"\u822a\u82d1\u5e97"), U(r"\u91d1\u6c99\u5e97"), U(r"\u5fae\u5e97"), U(r"\u7f51\u5e97"), U(r"\u5168\u90e8\u5e93\u5b58")]:
            if store in text:
                return store
        return text

    def store_alias_map(self, conn):
        rows = conn.execute("select canonical_store_name, alias_name from store_aliases where status='active'").fetchall()
        return {(r["alias_name"] or "").strip(): (r["canonical_store_name"] or "").strip() for r in rows if (r["alias_name"] or "").strip()}

    def brand_alias_map(self, conn):
        rows = conn.execute("select canonical_brand_name, alias_name from brand_aliases where status='active'").fetchall()
        mapping = {}
        for r in rows:
            alias = (r["alias_name"] or "").strip()
            if alias:
                mapping[alias.lower()] = (r["canonical_brand_name"] or "").strip()
        return mapping

    def canonical_store_name(self, conn, value):
        text = self.normalize_store_name(value)
        if not text:
            return ""
        mapping = self.store_alias_map(conn)
        return mapping.get(text, text)

    def infer_brand_name(self, text):
        hay = (text or "").lower()
        for label, keys in [
            ("Kailas", ["kailas", U(r"\u51ef\u4e50\u77f3")]),
            ("Osprey", ["osprey"]),
            ("Mammut", ["mammut", U(r"\u731b\u72b8\u8c61")]),
            ("VAFOX", ["vafox", U(r"\u706b\u72d0\u72f8")]),
            ("VauDe", ["vaude", U(r"\u6c83\u5fb7")]),
        ]:
            if any(k.lower() in hay for k in keys):
                return label
        return ""

    def canonical_brand_name(self, conn, value, product_text=""):
        text = (value or "").strip() or self.infer_brand_name(product_text)
        if not text:
            return ""
        mapping = self.brand_alias_map(conn)
        return mapping.get(text.lower(), self.infer_brand_name(text) or text)

    def product_canonical_key(self, normalized):
        code = str((normalized or {}).get("product_code") or "").strip()
        barcode = str((normalized or {}).get("barcode") or "").strip()
        name = re.sub(r"\s+", " ", str((normalized or {}).get("product_name") or "").strip()).lower()
        if code:
            return "product_code:" + code
        if barcode:
            return "barcode:" + barcode
        if name:
            return "product_name:" + name
        return ""

    def object_canonical_key(self, conn, object_type, object_name, match_key="", evidence=None):
        evidence = evidence or {}
        normalized = evidence.get("normalized") if isinstance(evidence, dict) else {}
        if object_type == "store":
            return "store:" + self.canonical_store_name(conn, object_name)
        if object_type == "brand":
            return "brand:" + self.canonical_brand_name(conn, object_name)
        if object_type == "product":
            product_key = self.product_canonical_key(normalized or {})
            return product_key or ("product:" + re.sub(r"\s+", " ", (object_name or "").strip()).lower())
        return "{}:{}".format(object_type, re.sub(r"\s+", " ", (object_name or "").strip()).lower())

    def find_enterprise_object(self, conn, object_type, name="", code=""):
        if code:
            row = conn.execute("select * from enterprise_objects where object_type=? and archived_at is null and coalesce(code,'')=?", (object_type, code)).fetchone()
            if row:
                return row
        if name:
            row = conn.execute("select * from enterprise_objects where object_type=? and archived_at is null and name=?", (object_type, name)).fetchone()
            if row:
                return row
        return None

    def create_object_suggestion(self, conn, object_type, object_name, source_type, source_id, evidence, confidence=0.7, canonical_key=""):
        if not object_name:
            return None
        now = ts()
        canonical_key = canonical_key or self.object_canonical_key(conn, object_type, object_name, "", evidence)
        existing = None
        if canonical_key:
            existing = conn.execute("select id from business_object_suggestions where object_type=? and canonical_key=?", (object_type, canonical_key)).fetchone()
        if not existing and not canonical_key:
            existing = conn.execute("select id from business_object_suggestions where object_type=? and object_name=? and source_type=? and source_id=?", (object_type, object_name, source_type, source_id)).fetchone()
        if existing:
            conn.execute("update business_object_suggestions set object_name=?, canonical_key=?, source_type=?, source_id=?, evidence=?, confidence=?, updated_at=? where id=?", (object_name, canonical_key, source_type, source_id, json.dumps(evidence or {}, ensure_ascii=False), confidence, now, existing["id"]))
            return existing["id"]
        cur = conn.execute(
            "insert into business_object_suggestions(object_type,object_name,canonical_key,source_type,source_id,evidence,confidence,status,created_at,updated_at) values(?,?,?,?,?,?,?,?,?,?)",
            (object_type, object_name, canonical_key, source_type, source_id, json.dumps(evidence or {}, ensure_ascii=False), confidence, "pending", now, now),
        )
        return cur.lastrowid

    def link_or_suggest_object(self, conn, source_id, record_type, record_id, object_type, object_name, match_key, evidence, code=""):
        if not object_name:
            return
        now = ts()
        canonical_key = self.object_canonical_key(conn, object_type, object_name, match_key, evidence)
        if object_type == "store":
            object_name = canonical_key.replace("store:", "", 1)
        elif object_type == "brand":
            object_name = canonical_key.replace("brand:", "", 1)
        obj = self.find_enterprise_object(conn, object_type, object_name, code)
        status = "matched" if obj else "suggested"
        object_id = obj["id"] if obj else None
        confidence = 0.95 if obj else 0.72
        existing = conn.execute("select id from business_object_links where record_type=? and record_id=? and object_type=? and match_key=?", (record_type, record_id, object_type, match_key)).fetchone()
        if existing:
            conn.execute("update business_object_links set object_id=?, match_confidence=?, match_status=?, updated_at=? where id=?", (object_id, confidence, status, now, existing["id"]))
        else:
            conn.execute(
                "insert into business_object_links(source_type,source_id,record_type,record_id,object_type,object_id,match_key,match_confidence,match_status,created_at,updated_at) values(?,?,?,?,?,?,?,?,?,?,?)",
                ("data_lake_record", source_id, record_type, record_id, object_type, object_id, match_key, confidence, status, now, now),
            )
        if not obj:
            suggestion_source_id = int(hashlib.sha1((canonical_key or object_name).encode("utf-8")).hexdigest()[:12], 16) % 2147483647
            self.create_object_suggestion(conn, object_type, object_name, "data_lake_canonical", suggestion_source_id, evidence, confidence, canonical_key)

    def data_lake_normalized_from_row(self, row, record_type):
        data = row_dict(row)
        if record_type == "sales":
            amount = float(data.get("amount") or 0)
            gross_profit = float(data.get("gross_profit") or 0)
            return {
                "sale_date": data.get("sale_date"),
                "store_name": self.normalize_store_name(data.get("store_name")),
                "store_code": data.get("store_code"),
                "employee_name": data.get("employee_name"),
                "brand_name": data.get("brand_name") or self.infer_brand_name(data.get("product_name")),
                "category_name": data.get("category_name"),
                "product_code": data.get("product_code"),
                "product_name": data.get("product_name"),
                "barcode": data.get("barcode"),
                "quantity": data.get("quantity") or 0,
                "amount": amount,
                "cost": data.get("cost") or 0,
                "gross_profit": gross_profit,
                "gross_margin": gross_profit / amount if amount else 0,
            }
        return {
            "snapshot_date": data.get("snapshot_date"),
            "store_name": self.normalize_store_name(data.get("store_name")),
            "store_code": data.get("store_code"),
            "brand_name": data.get("brand_name") or self.infer_brand_name(data.get("product_name")),
            "category_name": data.get("category_name"),
            "product_code": data.get("product_code"),
            "product_name": data.get("product_name"),
            "barcode": data.get("barcode"),
            "quantity": data.get("quantity") or 0,
            "cost_amount": data.get("cost_amount") or 0,
            "retail_amount": data.get("retail_amount") or 0,
            "age_days": data.get("age_days"),
        }

    def data_lake_quality(self, normalized, record_type):
        issues = []
        if record_type == "sales" and not normalized.get("amount"):
            issues.append("missing_amount")
        if record_type == "inventory" and normalized.get("quantity") in ("", None):
            issues.append("missing_quantity")
        if not normalized.get("product_code") and not normalized.get("barcode") and not normalized.get("product_name"):
            issues.append("missing_product_identity")
        return ("warning" if issues else "ok"), ",".join(issues)

    def rebuild_data_lake_for_batch(self, conn, batch, user_id=None):
        now = ts()
        batch_id = batch["id"]
        file_hash = ""
        document_id = batch["document_id"] if "document_id" in batch.keys() else None
        if document_id:
            doc = conn.execute("select storage_path,file_path from documents where id=?", (document_id,)).fetchone()
            file_path = (doc["storage_path"] or doc["file_path"]) if doc else ""
            if file_path and os.path.exists(file_path):
                file_hash = hashlib.sha256(Path(file_path).read_bytes()).hexdigest()
        existing = conn.execute("select * from data_lake_sources where batch_id=?", (batch_id,)).fetchone()
        if existing:
            source_id = existing["id"]
            conn.execute("update data_lake_sources set row_count=?, file_hash=?, status=?, updated_at=? where id=?", (batch["row_count"] or 0, file_hash, "rebuilt", now, source_id))
        else:
            cur = conn.execute(
                "insert into data_lake_sources(source_type,source_name,document_id,batch_id,filename,file_hash,encoding,delimiter,status,row_count,created_by,created_at,updated_at) values(?,?,?,?,?,?,?,?,?,?,?,?,?)",
                ("sap_import", batch["filename"] or ("batch-" + str(batch_id)), document_id, batch_id, batch["filename"], file_hash, "source_detected", "source_detected", "active", batch["row_count"] or 0, user_id, now, now),
            )
            source_id = cur.lastrowid
        created = 0
        warnings = 0
        for record_type, rows in (("sales", conn.execute("select * from sap_sales where batch_id=? order by id", (batch_id,)).fetchall()), ("inventory", conn.execute("select * from sap_inventory where batch_id=? order by id", (batch_id,)).fetchall())):
            for idx, row in enumerate(rows, 1):
                normalized = self.data_lake_normalized_from_row(row, record_type)
                normalized["store_name"] = self.canonical_store_name(conn, normalized.get("store_name"))
                normalized["brand_name"] = self.canonical_brand_name(conn, normalized.get("brand_name"), normalized.get("product_name"))
                normalized["product_key"] = self.product_canonical_key(normalized)
                row_hash = self.data_lake_hash({"batch_id": batch_id, "record_type": record_type, "raw_id": row["id"], "raw_data": row["raw_data"], "normalized": normalized})
                quality_status, quality_message = self.data_lake_quality(normalized, record_type)
                warnings += 1 if quality_status != "ok" else 0
                existing_record = conn.execute("select id from data_lake_records where batch_id=? and record_type=? and row_hash=?", (batch_id, record_type, row_hash)).fetchone()
                if existing_record:
                    record_id = existing_record["id"]
                    conn.execute("update data_lake_records set normalized_data=?, quality_status=?, quality_message=? where id=?", (json.dumps(normalized, ensure_ascii=False), quality_status, quality_message, record_id))
                else:
                    cur = conn.execute(
                        "insert into data_lake_records(source_id,batch_id,record_type,row_index,row_hash,raw_data,normalized_data,quality_status,quality_message,created_at) values(?,?,?,?,?,?,?,?,?,?)",
                        (source_id, batch_id, record_type, idx, row_hash, row["raw_data"], json.dumps(normalized, ensure_ascii=False), quality_status, quality_message, now),
                    )
                    record_id = cur.lastrowid
                    created += 1
                    conn.execute("insert into data_lake_lineage(source_id,record_id,target_type,target_id,relation_type,metadata,created_at) values(?,?,?,?,?,?,?)", (source_id, record_id, "sap_" + record_type, row["id"], "derived_from", json.dumps({"batch_id": batch_id}, ensure_ascii=False), now))
                evidence = {"batch_id": batch_id, "record_id": record_id, "record_type": record_type, "normalized": normalized}
                self.link_or_suggest_object(conn, source_id, record_type, record_id, "store", normalized.get("store_name") or "", "store_name", evidence)
                self.link_or_suggest_object(conn, source_id, record_type, record_id, "product", normalized.get("product_name") or normalized.get("product_code") or "", "product_code:" + str(normalized.get("product_code") or normalized.get("barcode") or normalized.get("product_name") or ""), evidence, normalized.get("product_code") or normalized.get("barcode") or "")
                self.link_or_suggest_object(conn, source_id, record_type, record_id, "brand", normalized.get("brand_name") or "", "brand_name", evidence)
        conn.execute("delete from data_quality_checks where batch_id=?", (batch_id,))
        conn.execute("insert into data_quality_checks(source_id,batch_id,check_key,status,message,affected_count,created_at) values(?,?,?,?,?,?,?)", (source_id, batch_id, "required_business_fields", "warning" if warnings else "ok", "rows with missing amount/quantity/product identity", warnings, now))
        self.refresh_business_metrics(conn)
        return {"source_id": source_id, "created_records": created, "warnings": warnings}

    def refresh_business_metrics(self, conn):
        now = ts()
        conn.execute("delete from business_metrics_snapshots")
        conn.execute("delete from business_metric_quality")
        batch_json = json.dumps([r["id"] for r in conn.execute("select id from sap_import_batches order by id").fetchall()], ensure_ascii=False)
        store_sales = {}
        for row in conn.execute("select coalesce(store_name,'') store_name, sum(coalesce(amount,0)) sales_amount, sum(coalesce(gross_profit,0)) gross_profit, sum(coalesce(quantity,0)) quantity from sap_sales group by store_name").fetchall():
            store = self.canonical_store_name(conn, row["store_name"])
            bucket = store_sales.setdefault(store, {"sales_amount": 0.0, "gross_profit": 0.0, "quantity": 0.0})
            bucket["sales_amount"] += float(row["sales_amount"] or 0)
            bucket["gross_profit"] += float(row["gross_profit"] or 0)
            bucket["quantity"] += float(row["quantity"] or 0)
        for store, bucket in store_sales.items():
            amount = bucket["sales_amount"]
            gross = bucket["gross_profit"]
            for key, value in [("sales_amount", amount), ("gross_profit", gross), ("gross_margin", gross / amount if amount else 0), ("sales_quantity", bucket["quantity"])]:
                conn.execute("insert into business_metrics_snapshots(snapshot_type,store_name,metric_key,metric_value,source_batch_ids,created_at) values(?,?,?,?,?,?)", ("store_sales", store, key, float(value or 0), batch_json, now))
        brand_sales = {}
        for row in conn.execute("select coalesce(brand_name,'') brand_name, sum(coalesce(amount,0)) sales_amount, sum(coalesce(gross_profit,0)) gross_profit from sap_sales group by brand_name").fetchall():
            if not row["brand_name"]:
                continue
            brand = self.canonical_brand_name(conn, row["brand_name"])
            bucket = brand_sales.setdefault(brand, {"sales_amount": 0.0, "gross_profit": 0.0})
            bucket["sales_amount"] += float(row["sales_amount"] or 0)
            bucket["gross_profit"] += float(row["gross_profit"] or 0)
        for brand, bucket in brand_sales.items():
            amount = bucket["sales_amount"]
            gross = bucket["gross_profit"]
            for key, value in [("sales_amount", amount), ("gross_profit", gross), ("gross_margin", gross / amount if amount else 0)]:
                conn.execute("insert into business_metrics_snapshots(snapshot_type,brand_name,metric_key,metric_value,source_batch_ids,created_at) values(?,?,?,?,?,?)", ("brand_sales", brand, key, float(value or 0), batch_json, now))
        store_inventory = {}
        for row in conn.execute("select coalesce(store_name,'') store_name, sum(coalesce(quantity,0)) quantity, sum(coalesce(cost_amount,0)) cost_amount, sum(coalesce(retail_amount,0)) retail_amount from sap_inventory group by store_name").fetchall():
            store = self.canonical_store_name(conn, row["store_name"])
            bucket = store_inventory.setdefault(store, {"quantity": 0.0, "cost_amount": 0.0, "retail_amount": 0.0})
            bucket["quantity"] += float(row["quantity"] or 0)
            bucket["cost_amount"] += float(row["cost_amount"] or 0)
            bucket["retail_amount"] += float(row["retail_amount"] or 0)
        for store, bucket in store_inventory.items():
            for key, value in [("inventory_quantity", bucket["quantity"]), ("inventory_cost_amount", bucket["cost_amount"]), ("inventory_retail_amount", bucket["retail_amount"])]:
                conn.execute("insert into business_metrics_snapshots(snapshot_type,store_name,metric_key,metric_value,source_batch_ids,created_at) values(?,?,?,?,?,?)", ("store_inventory", store, key, float(value or 0), batch_json, now))
            if bucket["quantity"] and bucket["retail_amount"] and not bucket["cost_amount"]:
                conn.execute(
                    "insert into business_metric_quality(metric_key,dimension_type,dimension_value,quality_status,quality_message,source_batch_ids,created_at) values(?,?,?,?,?,?,?)",
                    ("inventory_cost_amount", "store", store, "warning", U(r"\u5e93\u5b58\u6709\u6570\u91cf\u548c\u96f6\u552e\u91d1\u989d\uff0c\u4f46\u6210\u672c\u91d1\u989d\u4e3a 0\uff0c\u6bdb\u5229\u53e3\u5f84\u9700\u4eba\u5de5\u786e\u8ba4\u3002"), batch_json, now),
                )

    def rebuild_data_lake(self, user=None):
        with db() as conn:
            results = [self.rebuild_data_lake_for_batch(conn, batch, user["id"] if user else None) for batch in conn.execute("select * from sap_import_batches order by id").fetchall()]
            summary = self.business_metrics_summary(conn)
        return {"ok": True, "rebuilt_batches": len(results), "results": results, "summary": summary, "safety": "file_import_only_no_production_sap_connection"}

    def business_metrics_summary(self, conn=None):
        own = conn is None
        if own:
            conn = db()
        try:
            count = lambda sql: int(conn.execute(sql).fetchone()["c"] or 0)
            return {
                "data_lake_sources": count("select count(*) c from data_lake_sources"),
                "data_lake_records": count("select count(*) c from data_lake_records"),
                "linked_objects": count("select count(*) c from business_object_links where match_status='matched'"),
                "suggested_objects": count("select count(*) c from business_object_suggestions where status='pending'"),
                "quality_alerts": count("select count(*) c from data_quality_checks where status!='ok'"),
                "sales_amount": float(conn.execute("select coalesce(sum(metric_value),0) v from business_metrics_snapshots where snapshot_type='store_sales' and metric_key='sales_amount'").fetchone()["v"] or 0),
                "gross_profit": float(conn.execute("select coalesce(sum(metric_value),0) v from business_metrics_snapshots where snapshot_type='store_sales' and metric_key='gross_profit'").fetchone()["v"] or 0),
                "gross_margin": float(conn.execute("select case when coalesce(sum(case when metric_key='sales_amount' then metric_value else 0 end),0)=0 then 0 else coalesce(sum(case when metric_key='gross_profit' then metric_value else 0 end),0)/sum(case when metric_key='sales_amount' then metric_value else 0 end) end v from business_metrics_snapshots where snapshot_type='store_sales'").fetchone()["v"] or 0),
                "fee_amount": float(conn.execute("select coalesce(sum(metric_value),0) v from business_metrics_snapshots where snapshot_type='store_sales' and metric_key='fee_amount'").fetchone()["v"] or 0),
                "profit_amount": float(conn.execute("select coalesce(sum(metric_value),0) v from business_metrics_snapshots where snapshot_type='store_sales' and metric_key='profit_amount'").fetchone()["v"] or 0),
                "inventory_cost_amount": float(conn.execute("select coalesce(sum(metric_value),0) v from business_metrics_snapshots where snapshot_type='store_inventory' and metric_key='inventory_cost_amount'").fetchone()["v"] or 0),
                "inventory_retail_amount": float(conn.execute("select coalesce(sum(metric_value),0) v from business_metrics_snapshots where snapshot_type='store_inventory' and metric_key='inventory_retail_amount'").fetchone()["v"] or 0),
                "inventory_quantity": float(conn.execute("select coalesce(sum(metric_value),0) v from business_metrics_snapshots where snapshot_type='store_inventory' and metric_key='inventory_quantity'").fetchone()["v"] or 0),
                "store_aliases": count("select count(*) c from store_aliases where status='active'"),
                "brand_aliases": count("select count(*) c from brand_aliases where status='active'"),
                "metric_quality_warnings": count("select count(*) c from business_metric_quality where quality_status!='ok'"),
                "top_store_sales": [row_dict(r) for r in conn.execute("select store_name, metric_value sales_amount from business_metrics_snapshots where snapshot_type='store_sales' and metric_key='sales_amount' order by metric_value desc limit 8").fetchall()],
                "top_brand_sales": [row_dict(r) for r in conn.execute("select brand_name, metric_value sales_amount from business_metrics_snapshots where snapshot_type='brand_sales' and metric_key='sales_amount' order by metric_value desc limit 8").fetchall()],
                "inventory_summary": [row_dict(r) for r in conn.execute("select store_name, metric_key, metric_value from business_metrics_snapshots where snapshot_type='store_inventory' order by store_name, metric_key").fetchall()],
                "quality_warnings": [row_dict(r) for r in conn.execute("select * from business_metric_quality where quality_status!='ok' order by created_at desc limit 20").fetchall()],
            }
        finally:
            if own:
                conn.close()

    def object_file_count(self, conn, object_type, object_id):
        row = conn.execute(
            "select count(*) c from documents where deleted_at is null and related_object_type=? and related_object_id=?",
            (object_type, object_id),
        ).fetchone()
        return row["c"] if row else 0

    def search_snippet(self, text, query="", size=180):
        text = re.sub(r"\s+", " ", str(text or "")).strip()
        if not text:
            return ""
        q = (query or "").strip().lower()
        if q and q in text.lower():
            idx = text.lower().find(q)
            start = max(0, idx - size // 3)
            return text[start : start + size]
        return summarize_text(text, size)

    def global_search_results(self, user, q, result_type="", category="", object_type="", status="", date_from="", date_to=""):
        q = (q or "").strip()
        if not q:
            return {"ok": True, "query": q, "total": 0, "results": [], "filters": {"type": result_type, "category": category, "object_type": object_type, "status": status}}
        like = "%" + q + "%"
        results = []
        want = lambda key: not result_type or result_type == key
        def in_date(row_time):
            try:
                value = int(row_time or 0)
            except Exception:
                return True
            if date_from:
                try:
                    if value < int(time.mktime(time.strptime(date_from, "%Y-%m-%d"))):
                        return False
                except Exception:
                    pass
            if date_to:
                try:
                    if value > int(time.mktime(time.strptime(date_to, "%Y-%m-%d"))) + 86399:
                        return False
                except Exception:
                    pass
            return True
        with db() as conn:
            if want("file"):
                where = ["deleted_at is null", "(coalesce(filename,'') like ? or coalesce(original_filename,'') like ? or coalesce(category,'') like ? or coalesce(tags,'') like ? or coalesce(ai_summary,'') like ? or coalesce(extracted_text,'') like ?)"]
                params = [like, like, like, like, like, like]
                if category:
                    where.append("category=?")
                    params.append(category)
                if object_type:
                    where.append("related_object_type=?")
                    params.append(object_type)
                if status:
                    where.append("processing_status=?")
                    params.append(status)
                for row in conn.execute("select * from documents where " + " and ".join(where) + " order by updated_at desc limit 50", params).fetchall():
                    if not in_date(row["updated_at"] or row["created_at"]):
                        continue
                    item = self.document_to_json(row)
                    results.append({"type": "file", "icon": "FILE", "id": item["id"], "title": item["original_filename"], "snippet": self.search_snippet(item.get("ai_summary") or item.get("extracted_text") or item.get("category"), q), "source": item.get("category") or "Drive", "related_object": "{} #{}".format(item.get("related_object_type") or "", item.get("related_object_id") or "").strip(), "url": "/api/drive/files/{}".format(item["id"]), "score": 0.85, "updated_at": item.get("updated_at")})
            if want("object"):
                where = ["archived_at is null", "(name like ? or coalesce(description,'') like ? or coalesce(tags,'') like ? or coalesce(ai_summary,'') like ? or coalesce(metadata,'') like ?)"]
                params = [like, like, like, like, like]
                if object_type:
                    where.append("object_type=?")
                    params.append(object_type)
                if status:
                    where.append("status=?")
                    params.append(status)
                for row in conn.execute("select * from enterprise_objects where " + " and ".join(where) + " order by updated_at desc limit 50", params).fetchall():
                    if not in_date(row["updated_at"]):
                        continue
                    results.append({"type": "object", "icon": "OBJ", "id": row["id"], "title": row["name"], "snippet": self.search_snippet((row["description"] or "") + " " + (row["ai_summary"] or "") + " " + (row["metadata"] or ""), q), "source": self.object_type_label(row["object_type"]), "related_object": "{} #{}".format(row["object_type"], row["id"]), "url": "/objects?id={}".format(row["id"]), "score": 0.9, "updated_at": row["updated_at"]})
            if want("knowledge"):
                where = ["deleted_at is null", "(title like ? or coalesce(content,body,'') like ? or coalesce(summary,'') like ? or coalesce(tags,'') like ?)"]
                params = [like, like, like, like]
                if category:
                    where.append("category=?")
                    params.append(category)
                if object_type:
                    where.append("object_type=?")
                    params.append(object_type)
                if status:
                    where.append("status=?")
                    params.append(status)
                for row in conn.execute("select * from knowledge_items where " + " and ".join(where) + " order by updated_at desc limit 50", params).fetchall():
                    if not self.can_view_knowledge(user, row) or not in_date(row["updated_at"]):
                        continue
                    results.append({"type": "knowledge", "icon": "KB", "id": row["id"], "title": row["title"], "snippet": self.search_snippet(row["summary"] or row["content"] or row["body"], q), "source": row["source_type"] or "knowledge", "related_object": "{} #{}".format(row["object_type"] or "", row["object_id"] or "").strip(), "url": "/knowledge/view?id={}".format(row["id"]), "score": 0.8, "updated_at": row["updated_at"]})
            if want("chunk"):
                for row in conn.execute("select * from document_chunks where content like ? or summary like ? order by updated_at desc limit 50", (like, like)).fetchall():
                    if not in_date(row["updated_at"]):
                        continue
                    doc = conn.execute("select * from documents where id=? and deleted_at is null", (row["document_id"],)).fetchone()
                    if not doc:
                        continue
                    if category and doc["category"] != category:
                        continue
                    if object_type and doc["related_object_type"] != object_type:
                        continue
                    results.append({"type": "chunk", "icon": "CHUNK", "id": row["id"], "title": (doc["original_filename"] or doc["title"] or "Document") + " / chunk " + str(row["chunk_index"]), "snippet": self.search_snippet(row["content"] or row["summary"], q), "source": "document_chunks", "related_object": "{} #{}".format(doc["related_object_type"] or "", doc["related_object_id"] or "").strip(), "url": "/api/documents/{}/chunks".format(row["document_id"]), "score": 0.7, "updated_at": row["updated_at"]})
            if want("memory"):
                where = ["archived_at is null", "(title like ? or coalesce(summary,'') like ? or coalesce(content,'') like ? or coalesce(reason,'') like ? or coalesce(decision,'') like ? or coalesce(tags,'') like ?)"]
                params = [like, like, like, like, like, like]
                if object_type:
                    where.append("related_object_type=?")
                    params.append(object_type)
                if status:
                    where.append("status=?")
                    params.append(status)
                for row in conn.execute("select * from enterprise_memories where " + " and ".join(where) + " order by updated_at desc limit 50", params).fetchall():
                    if not in_date(row["updated_at"]):
                        continue
