    def record_save(self):
        user = self.current_user()
        if not user:
            return self.redir("/login")
        form = self.form()
        module = module_key(form.get("module"))
        if not self.record_allowed(user, module):
            return self.dashboard(user)
        rid = form.get("id", "").strip()
