    def admin_update(self):
        user = self.require_admin()
        if not user:
            return
        form = self.form()
        role = form.get("role", "employee") if form.get("role") in ROLES else "employee"
        status = form.get("status", "pending") if form.get("status") in STATUS else "pending"
        with db() as conn:
            conn.execute("update users set role=?, status=?, updated_at=? where id=?", (role, status, int(time.time()), form.get("id")))
        return self.redir("/admin")

    def admin_reset_password(self):
        user = self.require_admin()
        if not user:
            return
        form = self.form()
        new_password = form.get("new_password", "")
        if len(new_password) < 6:
            return self.admin(U(r"\u65b0\u5bc6\u7801\u81f3\u5c11 6 \u4f4d\u3002"))
        with db() as conn:
            conn.execute(
                "update users set password_hash=?, failed_attempts=0, locked_until=0, reset_required=1, updated_at=? where id=?",
                (hp(new_password), int(time.time()), form.get("id")),
            )
        return self.redir("/admin")

    def ceo_dashboard_payload(self, user):
        def count(conn, sql, params=()):
            try:
                row = conn.execute(sql, params).fetchone()
                return int(row["c"] if row and "c" in row.keys() else 0)
            except Exception:
                return 0

        def safe_rows(conn, sql, params=()):
            try:
                return [row_dict(r) for r in conn.execute(sql, params).fetchall()]
            except Exception:
                return []

        status = []
        with db() as conn:
            documents_total = count(conn, "select count(*) c from documents where deleted_at is null")
            documents_pending = count(conn, "select count(*) c from documents where deleted_at is null and processing_status in ('pending','uploaded','processing','extracting','failed')")
            documents_processed = count(conn, "select count(*) c from documents where deleted_at is null and processing_status in ('processed','indexed','ready')")
