                self.card(U(r"\u95e8\u5e97"), U(r"\u9500\u552e\u3001\u6bdb\u5229\u3001\u5e93\u5b58\u3001\u5458\u5de5\u548c\u98ce\u9669\u3002"), "/object-center?type=store", "btn", True),
