                self.card(U(r"\u54c1\u724c\u751f\u547d"), U(r"\u54c1\u724c\u6545\u4e8b\u3001\u4eba\u624d\u3001\u95e8\u5e97\u3001\u57f9\u8bad\u4e0e\u77e5\u8bc6\u8d44\u4ea7\u3002"), "/brand-life/kailas", "btn", True),
