                self.card(U(r"\u4f01\u4e1a\u77e5\u8bc6\u7f51\u7edc"), U(r"\u67e5\u770b\u6709\u6765\u6e90\u3001\u53ef\u8ffd\u6eaf\u7684\u4f01\u4e1a\u5173\u7cfb\u3002"), "/enterprise-network", "btn", True),
