                self.metric(U(r"\u8d39\u7528"), money(summary.get("fee_amount", 0)), U(r"2026 \u5e74\u7ecf\u8425\u53e3\u5f84")),
                self.metric(U(r"\u5229\u6da6"), money(summary.get("profit_amount", 0)), U(r"\u542b\u54c1\u724c\u8fd4\u70b9")),
