    def api_sap_sync_get(self, user, path):
        if not user:
            return self.json_out({"ok": False, "message": "login required"}, code=401)
        if not self.can_manage_sap_sync(user):
            return self.json_out({"ok": False, "message": "no permission"}, code=403)
        if path == "/api/sap/sync/connector":
            return self.json_out(self.sap_connector_payload())
        if path == "/api/sap/sync/status":
            return self.json_out(self.sap_sync_status_payload())
        if path == "/api/sap/sync/history":
            return self.json_out({"ok": True, "history": self.sap_sync_status_payload()["history"]})
        if path == "/api/sap/sync/health":
            s = self.sap_sync_status_payload()
            return self.json_out({"ok": True, "scheduler_enabled": s["enabled"], "freshness": s["freshness"], "last_status": s["last_status"], "next_run_time": s["next_run_time"]})
        if path.startswith("/api/sap/sync/logs/"):
            return self.json_out({"ok": True, "message": U(r"\u65e5\u5fd7\u8def\u5f84\u4ec5\u663e\u793a\u5b89\u5168\u5360\u4f4d\uff0c\u4e0d\u8fd4\u56de\u8fde\u63a5\u4e32\u6216\u5bc6\u94a5\u3002"), "log": ""})
        if path == "/api/data-pipeline":
            return self.json_out(self.data_pipeline_payload())
        if path == "/api/system/data-freshness":
            s = self.sap_sync_status_payload()
            return self.json_out({"ok": True, "sap_data_freshness": s["freshness"], "warning": s["warning"]})
        return self.json_out({"ok": False, "message": "unknown sap sync api"}, code=404)

    def api_data_lake_get(self, user, path):
        if not user:
            return self.json_out({"ok": False, "message": "login required"}, code=401)
        if not self.can_open(user, ("boss", "admin", "finance", "purchasing", "store_manager")):
            return self.json_out({"ok": False, "message": "no permission"}, code=403)
        query = parse_qs(urlparse(self.path).query)
        if path == "/api/data-lake/sources":
            with db() as conn:
                rows = conn.execute("select * from data_lake_sources order by updated_at desc limit 300").fetchall()
            return self.json_out({"ok": True, "sources": [row_dict(r) for r in rows]})
        if path == "/api/data-lake/records":
            record_type = query.get("type", [""])[0]
            where, params = ["1=1"], []
            if record_type:
                where.append("record_type=?")
                params.append(record_type)
            with db() as conn:
                rows = conn.execute("select * from data_lake_records where " + " and ".join(where) + " order by id desc limit 500", params).fetchall()
            return self.json_out({"ok": True, "records": [row_dict(r) for r in rows]})
        if path == "/api/object-links":
            with db() as conn:
                rows = conn.execute("select * from business_object_links order by updated_at desc limit 500").fetchall()
            return self.json_out({"ok": True, "links": [row_dict(r) for r in rows]})
        if path == "/api/object-suggestions":
            with db() as conn:
                rows = conn.execute("select * from business_object_suggestions order by updated_at desc limit 500").fetchall()
            return self.json_out({"ok": True, "suggestions": [row_dict(r) for r in rows]})
        if path == "/api/business-metrics/summary":
            return self.json_out({"ok": True, "summary": self.business_metrics_summary()})
        if path == "/api/business-calibration/summary":
            return self.json_out({"ok": True, "summary": self.business_metrics_summary(), "safety": "file_import_only_no_production_sap_connection"})
        if path == "/api/business-calibration/store-aliases":
            with db() as conn:
                rows = conn.execute("select * from store_aliases order by canonical_store_name, alias_name").fetchall()
            return self.json_out({"ok": True, "store_aliases": [row_dict(r) for r in rows]})
        if path == "/api/business-calibration/brand-aliases":
            with db() as conn:
                rows = conn.execute("select * from brand_aliases order by canonical_brand_name, alias_name").fetchall()
            return self.json_out({"ok": True, "brand_aliases": [row_dict(r) for r in rows]})
        if path == "/api/business-calibration/quality":
            with db() as conn:
                rows = conn.execute("select * from business_metric_quality order by created_at desc limit 300").fetchall()
            return self.json_out({"ok": True, "quality": [row_dict(r) for r in rows]})
        return self.json_out({"ok": False, "message": "unknown data lake api"}, code=404)

    def api_data_lake_post(self, user, path):
        if not user:
            return self.json_out({"ok": False, "message": "login required"}, code=401)
        if not self.can_open(user, ("boss", "admin", "finance", "purchasing", "store_manager")):
            return self.json_out({"ok": False, "message": "no permission"}, code=403)
        if path == "/api/data-lake/rebuild":
            payload = self.rebuild_data_lake(user)
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/data-lake")
            return self.json_out(payload)
        if path == "/api/business-calibration/rebuild":
            payload = self.rebuild_data_lake(user)
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/business-calibration")
            return self.json_out(payload)
        m_approve = re.match(r"^/api/object-suggestions/(\d+)/approve$", path)
        if m_approve:
            now = ts()
            with db() as conn:
                row = conn.execute("select * from business_object_suggestions where id=?", (m_approve.group(1),)).fetchone()
                if not row:
                    return self.json_out({"ok": False, "message": "not found"}, code=404)
                obj = self.find_enterprise_object(conn, row["object_type"], row["object_name"], "")
                object_id = obj["id"] if obj else None
                if not object_id:
                    cur = conn.execute(
                        "insert into enterprise_objects(object_type,name,code,description,status,tags,metadata,ai_summary,created_by,created_at,updated_at,archived_at) values(?,?,?,?,?,?,?,?,?,?,?,?)",
                        (row["object_type"], row["object_name"], "", U(r"\u7531 Data Lake \u5bf9\u8c61\u5339\u914d\u4e2d\u5fc3\u4eba\u5de5\u786e\u8ba4\u521b\u5efa\u3002"), "active", "data-lake", row["evidence"] or "{}", "", user["id"], now, now, None),
                    )
                    object_id = cur.lastrowid
                conn.execute("update business_object_suggestions set status='approved', reviewed_by=?, reviewed_at=?, updated_at=? where id=?", (user["id"], now, now, row["id"]))
                conn.execute("update business_object_links set object_id=?, match_status='matched', match_confidence=1.0, updated_at=? where object_type=? and source_id=? and match_status='suggested'", (object_id, now, row["object_type"], row["source_id"]))
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/object-suggestions")
            return self.json_out({"ok": True, "object_id": object_id})
        m_reject = re.match(r"^/api/object-suggestions/(\d+)/reject$", path)
        if m_reject:
            now = ts()
            with db() as conn:
                conn.execute("update business_object_suggestions set status='rejected', reviewed_by=?, reviewed_at=?, updated_at=? where id=?", (user["id"], now, now, m_reject.group(1)))
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/object-suggestions")
            return self.json_out({"ok": True})
        return self.json_out({"ok": False, "message": "unknown data lake write api"}, code=404)

    def api_sap_knowledge_engine_get(self, user, path):
        if not user:
            return self.json_out({"ok": False, "message": "login required"}, code=401)
        if user["role"] not in ("boss", "admin", "finance", "purchasing", "store_manager"):
            return self.json_out({"ok": False, "message": "no permission"}, code=403)
        payload = self.sap_knowledge_engine_payload(user)
        if path in ("/api/sap-knowledge-engine", "/api/sap-knowledge-engine/status"):
            return self.json_out(payload)
        if path == "/api/sap-knowledge-engine/contract":
            return self.json_out(payload["contract"])
        if path in ("/api/sap-knowledge-engine/read-only-sync", "/api/sap-knowledge-engine/sync-layer"):
            return self.json_out({"ok": True, "read_only_sync_layer": payload["read_only_sync_layer"], "production_boundary": payload["production_boundary"]})
        if path in ("/api/sap-knowledge-engine/warehouse", "/api/sap-knowledge-engine/ai-warehouse"):
            return self.json_out(payload["ai_data_warehouse"])
        if path in ("/api/sap-knowledge-engine/models", "/api/sap-knowledge-engine/model-catalog"):
            return self.json_out(payload["knowledge_models"])
        m = re.match(r"^/api/sap-knowledge-engine/models/(product|sales|inventory|member)$", path)
        if m:
            return self.json_out(build_model_catalog(m.group(1)))
        return self.json_out({"ok": False, "message": "unknown sap knowledge engine api"}, code=404)

    def api_knowledge_quality_get(self, user, path):
        if not user:
            return self.json_out({"ok": False, "message": "login required"}, code=401)
        if user["role"] not in ("boss", "admin", "finance", "purchasing", "store_manager"):
            return self.json_out({"ok": False, "message": "no permission"}, code=403)
        payload = self.knowledge_training_quality_payload(user)
        if path in ("/api/knowledge-quality", "/api/knowledge-quality/status", "/api/ai-learning", "/api/boss-experience"):
            return self.json_out(payload)
        if path == "/api/knowledge-quality/contract":
            return self.json_out(payload["contract"])
        if path == "/api/knowledge-quality/score":
            return self.json_out(payload["knowledge_quality"])
        if path in ("/api/ai-learning/plan", "/api/knowledge-quality/learning-plan"):
            return self.json_out(payload["ai_learning"])
        if path in ("/api/boss-experience/memory", "/api/knowledge-quality/boss-experience"):
            return self.json_out(payload["boss_experience"])
        return self.json_out({"ok": False, "message": "unknown knowledge quality api"}, code=404)

    def api_sap_sync_post(self, user, path):
        if path == "/api/sap/sync/run":
            result, code = self.run_sap_sync_stub("manual", user)
            return self.json_out(result, code=code)
        if path.startswith("/api/sap/sync/retry/"):
            sync_id = path.rsplit("/", 1)[-1]
            result, code = self.run_sap_sync_stub("retry", user, retry_sync_id=sync_id)
            return self.json_out(result, code=code)
        return self.json_out({"ok": False, "message": "unknown sap sync write api"}, code=404)

    def api_enterprise_sync_get(self, user, path):
        if not user:
            return self.json_out({"ok": False, "message": "login required"}, code=401)
        if not self.can_manage_sap_sync(user):
            return self.json_out({"ok": False, "message": "no permission"}, code=403)
        payload = self.enterprise_sync_payload()
        if path in ("/api/sync", "/api/sync/status", "/api/sync/center"):
            return self.json_out(payload)
        if path == "/api/sync/connections":
            return self.json_out({"ok": True, "connections": payload["connections"], "safety": payload["safety"]})
        if path == "/api/sync/jobs":
            return self.json_out({"ok": True, "jobs": payload["jobs"], "schedules_enabled_by_default": False})
        if path == "/api/sync/runs":
            return self.json_out({"ok": True, "runs": payload["runs"]})
        if path == "/api/sync/reconciliation":
            return self.json_out({"ok": True, "reconciliation": payload["reconciliation"]})
        if path == "/api/sync/mappings":
            return self.json_out({"ok": True, "mappings": payload["mappings"]})
        if path == "/api/sync/freshness":
            return self.json_out({"ok": True, "freshness": payload["freshness"]})
        m = re.match(r"^/api/sync/runs/(\d+)/reconciliation$", path)
        if m:
            with db() as conn:
                rows = self.enterprise_sync_reconciliation_for_run(conn, int(m.group(1)))
            return self.json_out({"ok": True, "run_id": int(m.group(1)), "reconciliation": rows})
        return self.json_out({"ok": False, "message": "unknown sync api"}, code=404)

    def api_enterprise_sync_post(self, user, path):
        if not user:
            return self.json_out({"ok": False, "message": "login required"}, code=401)
        if not self.can_manage_sap_sync(user):
            return self.json_out({"ok": False, "message": "no permission"}, code=403)
        if path == "/api/sync/environment/test":
            payload = self.enterprise_sync_payload()
            result = {"ok": True, "environment": payload["environment"], "safety": payload["safety"], "message": "No production SAP connection attempted in coding simulation."}
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/sync-center")
            return self.json_out(result)
        if path == "/api/sync/readonly/verify":
            payload, code = self.enterprise_sync_verify_readonly_environment(user)
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/sync-center")
            return self.json_out(payload, code=code)
        if path == "/api/sync/dry-run":
            results = []
            with db() as conn:
                self.ensure_enterprise_sync_defaults(conn)
                jobs = conn.execute("select id,dataset_type from sync_jobs where dataset_type in ('sales','inventory','products','brands','stores') order by id").fetchall()
            for job in jobs:
                payload, code = self.enterprise_sync_run_job(job["id"], user, "full_dry_run")
                results.append({"dataset_type": job["dataset_type"], "code": code, "result": payload})
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/sync-center")
            return self.json_out({"ok": all(r["result"].get("ok") for r in results), "results": results, "published": False, "cursor_advanced": False})
        m = re.match(r"^/api/sync/connections/(\d+)/test$", path)
        if m:
            payload, code = self.enterprise_sync_test_connection(int(m.group(1)), user)
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/sync-center")
            return self.json_out(payload, code=code)
        m = re.match(r"^/api/sync/connections/(\d+)/verify-readonly$", path)
        if m:
            payload, code = self.enterprise_sync_verify_readonly(int(m.group(1)), user)
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/sync-center")
            return self.json_out(payload, code=code)
        m = re.match(r"^/api/sync/jobs/(\d+)/(dry-run|full-dry-run|incremental)$", path)
        if m:
            run_type = {"dry-run": "dry_run", "full-dry-run": "full_dry_run", "incremental": "incremental_sync"}[m.group(2)]
            payload, code = self.enterprise_sync_run_job(int(m.group(1)), user, run_type)
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/sync-center")
            return self.json_out(payload, code=code)
        m = re.match(r"^/api/sync/runs/(\d+)/publish$", path)
        if m:
            payload, code = self.enterprise_sync_publish_run(int(m.group(1)), user)
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/sync-center")
            return self.json_out(payload, code=code)
        m = re.match(r"^/api/sync/runs/(\d+)/approve$", path)
        if m:
            payload, code = self.enterprise_sync_approve_run(int(m.group(1)), user)
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/sync-center")
            return self.json_out(payload, code=code)
        m = re.match(r"^/api/sync/runs/(\d+)/rollback$", path)
        if m:
            payload, code = self.enterprise_sync_rollback_run(int(m.group(1)), user)
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/sync-center")
            return self.json_out(payload, code=code)
        m = re.match(r"^/api/sync/runs/(\d+)/discard$", path)
        if m:
            with db() as conn:
                conn.execute("update sync_runs set status='discarded',updated_at=? where id=? and status!='published'", (ts(), int(m.group(1))))
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/sync-center")
            return self.json_out({"ok": True, "run_id": int(m.group(1)), "status": "discarded"})
        m = re.match(r"^/api/sync/runs/(\d+)/retry$", path)
        if m:
            with db() as conn:
                run = conn.execute("select * from sync_runs where id=?", (int(m.group(1)),)).fetchone()
            if not run:
                return self.json_out({"ok": False, "message": "sync run not found"}, code=404)
            payload, code = self.enterprise_sync_run_job(int(run["job_id"]), user, run["run_type"] or "dry_run")
            if "text/html" in (self.headers.get("Accept") or ""):
                return self.redir("/sync-center")
            return self.json_out(payload, code=code)
        return self.json_out({"ok": False, "message": "unknown sync write api"}, code=404)

    def app_permission_status(self, user, permission_required):
        if not user:
            return "login_required"
        role = user["role"]
        if role == "admin":
            return "allowed"
        if permission_required in ("view_workspace", "employee") and role in ("boss", "finance", "purchasing", "store_manager", "employee"):
            return "allowed"
        if permission_required == "boss" and role in ("boss", "finance", "purchasing"):
            return "allowed"
        if permission_required == "store_manager" and role in ("boss", "finance", "purchasing", "store_manager"):
            return "allowed"
        if permission_required == "finance" and role in ("boss", "finance"):
            return "allowed"
        if permission_required == "purchasing" and role in ("boss", "purchasing", "finance"):
            return "allowed"
        return "disabled"

    def os_apps_payload(self, user):
        readiness = {x["area"]: x["level"] for x in self.data_readiness_payload()}
        apps = []
        category_map = {"ai": "AI Command", "operation": "Business Operations", "knowledge": "Knowledge & Data", "execution": "Execution", "system": "System"}
        for key, name, route, category, permission in self.platform_modules():
            status = self.app_permission_status(user, permission)
            apps.append({"module_key": key, "app_name": name, "route": route, "category": category_map.get(category, category), "status": "healthy", "permission_status": status, "data_readiness": readiness.get("sap_data", "partial" if category != "system" else "ready"), "description": key.replace("_", " ")})
        return {"ok": True, "apps": apps, "data_freshness": self.sap_sync_status_payload()["freshness"]}

