    def portal_role_profile(self, user):
        role = user["role"]
        if role in ("boss", "finance", "purchasing"):
            portal = "CEO"
            home = "/boss"
        elif role == "store_manager":
            portal = "Store Manager"
            home = "/desktop"
        elif role == "admin":
            portal = "Admin"
            home = "/system/modules"
        elif role == "employee":
            portal = "Employee"
            home = "/employee-workspace"
        else:
            portal = "Employee"
            home = "/portal"
        return {"role": role, "portal": portal, "home": home}

