        domain = plan_request.get("domain") or find_agent_domain(domain_key)
        title = U(r"V1.2 \u667a\u80fd\u4f53\u5f85\u5ba1\u6279\u8ba1\u5212\uff1a") + str(domain.get("name") or domain.get("key") or domain_key)
